import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p.get('resolvedVersion', p.get('requestedVersion',''))
        result[name] = pkgs
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)

changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for pkg in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bv = b.get(proj,{}).get(pkg)
        av = a.get(proj,{}).get(pkg)
        if bv != av:
            changes.append((proj, pkg, bv or 'N/A', av or 'N/A'))
        else:
            unchanged.append((proj, pkg, bv))

print('=== CHANGES ===')
for c in changes:
    print(f'  {c[0]}: {c[1]} {c[2]} -> {c[3]}')
if not changes:
    print('  None')
print()
print(f'=== UNCHANGED: {len(unchanged)} package-project pairs ===')
"

